        {loading ? (
           <p>Loading users...</p>
        ) : users.length === 0 ? (
           <p>No users found matching your filters.</p>
        ) : (
          <>
            <table className="data-table">
              <thead>
                <tr>
                  <th>Name</th>
                  <th>Email</th>
                  <th>Role</th>
                  <th>Actions</th>
                </tr>
              </thead>
