import { useEffect, useState, useCallback } from 'react';
import { createResource, deleteResource, getMyResources, updateResource } from '../services/resourceService';
import AddResourceForm from '../components/resources/AddResourceForm';
import EditResourceModal from '../components/resources/EditResourceModal';
import ResourceList from '../components/resources/ResourceList';
import Pagination from '../components/Pagination/Pagination';
import FilterPanel from '../components/Filters/FilterPanel';
import SortDropdown from '../components/Filters/SortDropdown';
import './Forms.css';
import './Cards.css';
import './Resources.css';
import './ResourceForm.css';
import './Tables.css';

function Resources() {
  const [resources, setResources] = useState([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [editingResource, setEditingResource] = useState(null);
  const [message, setMessage] = useState('');
  const [messageType, setMessageType] = useState('');

  // Pagination & Filters State
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);
  const [hasNextPage, setHasNextPage] = useState(false);
  const [hasPrevPage, setHasPrevPage] = useState(false);

  const [currentSort, setCurrentSort] = useState('latest');
  const [currentFilters, setCurrentFilters] = useState({});

  const loadResources = useCallback(async () => {
    setLoading(true);
    try {
      const params = {
        page,
        limit: 5,
        sort: currentSort,
        search: currentFilters.search || '',
        resourceType: currentFilters.resourceType || '',
      };

      const data = await getMyResources(params);
      setResources(data.data || []);
      setTotalPages(data.totalPages || 1);
      setTotalItems(data.totalItems || 0);
      setHasNextPage(data.hasNextPage || false);
      setHasPrevPage(data.hasPrevPage || false);
    } catch (err) {
      console.error('Failed to load resources', err);
    } finally {
      setLoading(false);
    }
  }, [page, currentSort, currentFilters]);

  useEffect(() => {
    loadResources();
  }, [loadResources]);

  const handleAdd = async (payload) => {
    setSaving(true);
    setMessage('');
    try {
      await createResource(payload);
      setMessage('Resource added successfully');
      setMessageType('success');
      setPage(1);
      await loadResources();
    } catch (error) {
      setMessage(error.response?.data?.message || 'Failed to add resource');
      setMessageType('error');
    } finally {
      setSaving(false);
    }
  };

  const handleEdit = (resource) => setEditingResource(resource);

  const handleUpdate = async (resourceId, payload) => {
    setSaving(true);
    try {
      await updateResource(resourceId, payload);
      setEditingResource(null);
      await loadResources();
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (resourceId) => {
    if (!window.confirm('Delete this resource?')) return;
    await deleteResource(resourceId);
    if (resources.length === 1 && page > 1) {
      setPage(page - 1);
    } else {
      await loadResources();
    }
  };

  const handleFilterChange = (id, value) => {
    setCurrentFilters(prev => ({ ...prev, [id]: value }));
    setPage(1);
  };

  const handleSearchChange = (value) => {
    setCurrentFilters(prev => ({ ...prev, search: value }));
    setPage(1);
  };

  const resourceFiltersConfig = [
    {
      id: 'resourceType',
      label: 'Type',
      options: [
        { value: 'water', label: 'Water' },
        { value: 'fertilizer', label: 'Fertilizer' },
        { value: 'pesticide', label: 'Pesticide' },
        { value: 'seeds', label: 'Seeds' },
        { value: 'labor', label: 'Labor' },
        { value: 'equipment', label: 'Equipment' }
      ]
    }
  ];

  const sortOptions = [
    { value: 'latest', label: 'Latest First' },
    { value: 'oldest', label: 'Oldest First' },
    { value: 'cost-desc', label: 'Highest Cost' },
    { value: 'cost-asc', label: 'Lowest Cost' },
  ];

  return (
    <section className="card resource-page">
      <div className="page-head">
        <div>
          <h1>Resources</h1>
          <p>Track farm inputs, costs, and usage history. Total: {totalItems}</p>
        </div>
      </div>

      <AddResourceForm onSubmit={handleAdd} loading={saving} />

      {message && <div className={`form-message ${messageType}`}>{message}</div>}

      <div className="filters-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '1rem', marginTop: '2rem' }}>
        <FilterPanel 
          filters={resourceFiltersConfig} 
          currentFilters={currentFilters} 
          onFilterChange={handleFilterChange}
          onSearchChange={handleSearchChange}
        />
        <SortDropdown 
          sortOptions={sortOptions} 
          currentSort={currentSort} 
          onSortChange={(val) => { setCurrentSort(val); setPage(1); }} 
        />
      </div>

      <ResourceList resources={resources} onEdit={handleEdit} onDelete={handleDelete} loading={loading} />

      {!loading && resources.length > 0 && (
        <Pagination 
          currentPage={page} 
          totalPages={totalPages} 
          onPageChange={setPage} 
          hasNextPage={hasNextPage} 
          hasPrevPage={hasPrevPage} 
        />
      )}

      <EditResourceModal
        resource={editingResource}
        onClose={() => setEditingResource(null)}
        onSubmit={handleUpdate}
        loading={saving}
      />
    </section>
  );
}

export default Resources;

import { useEffect, useState } from 'react';
import { useSearchParams, useNavigate, Link } from 'react-router-dom';
import api from '../services/api';
import './Search.css';

function SearchPage() {
  const [searchParams] = useSearchParams();
  const query = searchParams.get('q') || '';
  const navigate = useNavigate();

  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('all');

  useEffect(() => {
    const fetchResults = async () => {
      if (!query) {
        setResults(null);
        return;
      }

      setLoading(true);
      setError('');

      try {
        const response = await api.get(`/search?query=${encodeURIComponent(query)}`);
        setResults(response.data);
        setActiveTab('all');
      } catch (err) {
        setError(err.response?.data?.message || 'Search failed');
      } finally {
        setLoading(false);
      }
    };

    fetchResults();
  }, [query]);

  const handleManualSearch = (e) => {
    e.preventDefault();
    const newQuery = new FormData(e.target).get('q');
    if (newQuery && newQuery.trim()) {
      navigate(`/search?q=${encodeURIComponent(newQuery.trim())}`);
    }
  };

  const renderTabContent = () => {
    if (!results) return null;

    let displayData = [];
    let titleBase = '';

    if (activeTab === 'all') {
      return (
        <div className="search-summary">
          <p>Found results in:</p>
          <ul className="search-summary-list">
            <li><button type="button" onClick={() => setActiveTab('crops')}>Crops ({results.totals.crops})</button></li>
            <li><button type="button" onClick={() => setActiveTab('resources')}>Resources ({results.totals.resources})</button></li>
            <li><button type="button" onClick={() => setActiveTab('activities')}>Activities ({results.totals.activities})</button></li>
            {results.totals.users > 0 && <li><button type="button" onClick={() => setActiveTab('users')}>Users ({results.totals.users})</button></li>}
          </ul>
        </div>
      );
    } else if (activeTab === 'crops') {
      displayData = results.crops;
      titleBase = 'Crop';
    } else if (activeTab === 'resources') {
      displayData = results.resources;
      titleBase = 'Resource';
    } else if (activeTab === 'activities') {
      displayData = results.activities;
      titleBase = 'Activity';
    } else if (activeTab === 'users') {
      displayData = results.users;
      titleBase = 'User';
    }

    if (displayData.length === 0) {
      return <p className="empty-state">No {activeTab} found for "{query}"</p>;
    }

    return (
      <div className="search-results-list">
        {displayData.map((item) => (
          <div key={item._id} className="search-result-card">
            <h4>{item.name || item.title || item.resourceType}</h4>
            <p className="search-result-meta">
              {item.type && <span>Type: {item.type}</span>}
              {item.stage && <span> • Stage: {item.stage}</span>}
              {item.status && <span>Status: {item.status}</span>}
              {item.quantity && <span>{item.quantity} {item.unit}</span>}
              {item.email && <span>Email: {item.email}</span>}
              {item.role && <span> • Role: {item.role}</span>}
            </p>
          </div>
        ))}
      </div>
    );
  };

  return (
    <section className="card search-page">
      <h1>Global Search</h1>

      <form onSubmit={handleManualSearch} className="search-page-form">
        <input 
          name="q" 
          type="search" 
          defaultValue={query} 
          placeholder="Search for crops, resources..." 
          className="search-page-input"
        />
        <button type="submit" className="primary-btn">Search</button>
      </form>

      {loading && <p>Searching...</p>}
      {error && <p className="form-message error">{error}</p>}

      {!loading && !error && results && (
        <div className="search-results-container">
          <div className="search-tabs">
            <button type="button" className={`tab-btn ${activeTab === 'all' ? 'active' : ''}`} onClick={() => setActiveTab('all')}>
              All Results
            </button>
            <button type="button" className={`tab-btn ${activeTab === 'crops' ? 'active' : ''}`} onClick={() => setActiveTab('crops')}>
              Crops ({results.totals.crops})
            </button>
            <button type="button" className={`tab-btn ${activeTab === 'resources' ? 'active' : ''}`} onClick={() => setActiveTab('resources')}>
              Resources ({results.totals.resources})
            </button>
            <button type="button" className={`tab-btn ${activeTab === 'activities' ? 'active' : ''}`} onClick={() => setActiveTab('activities')}>
              Activities ({results.totals.activities})
            </button>
            {results.totals.users > 0 && (
              <button type="button" className={`tab-btn ${activeTab === 'users' ? 'active' : ''}`} onClick={() => setActiveTab('users')}>
                Users ({results.totals.users})
              </button>
            )}
          </div>

          <div className="tab-content">
            {renderTabContent()}
          </div>
        </div>
      )}

      {!query && !loading && (
        <p className="empty-state">Enter a query above to start searching</p>
      )}
    </section>
  );
}

export default SearchPage;

